import{_ as e,o as s,c as n,a5 as t}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"概念：UPS 命令解析与安全门控（command parsing and safety gating）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：UPS 命令解析与安全门控（command parsing and safety gating）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0032-ups-command-parser.html` 的源稿和补充资料。它只使用教学命令，不包含公司内部通信命令、寄存器地址、客户项目参数或未公开产品方案。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-command-parser.md","filePath":"content/power/concepts/embedded/ups-command-parser.md","lastUpdated":null}'),l={name:"content/power/concepts/embedded/ups-command-parser.md"};function i(o,a,p,d,c,r){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="概念-ups-命令解析与安全门控-command-parsing-and-safety-gating" tabindex="-1">概念：UPS 命令解析与安全门控（command parsing and safety gating） <a class="header-anchor" href="#概念-ups-命令解析与安全门控-command-parsing-and-safety-gating" aria-label="Permalink to &quot;概念：UPS 命令解析与安全门控（command parsing and safety gating）&quot;">​</a></h1><p>本页是 <code>lessons/0032-ups-command-parser.html</code> 的源稿和补充资料。它只使用教学命令，不包含公司内部通信命令、寄存器地址、客户项目参数或未公开产品方案。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>命令解析（command parsing）是把外部通信收到的文本、字节或寄存器请求转换成固件内部动作意图的过程。安全门控（safety gating）是在动作真正生效前，再检查系统是否满足安全条件。</p><p>本课只讲一个概念：通信命令不能直接改安全状态。教学命令只包含两类：</p><ul><li><code>READ_STATUS</code>：请求遥测（telemetry）回复。</li><li><code>CLEAR_FAULT_REQUEST</code>：清故障请求（clear fault request），必须经过安全门控后才能变成真正的清故障动作。</li></ul><h2 id="为什么-ups-需要它" tabindex="-1">为什么 UPS 需要它 <a class="header-anchor" href="#为什么-ups-需要它" aria-label="Permalink to &quot;为什么 UPS 需要它&quot;">​</a></h2><p>UPS 通信模块会收到外部工具、监控系统或调试脚本发来的请求。如果通信命令绕过保护逻辑，直接清除故障锁存（fault latch）或打开输出，就会破坏系统安全边界。</p><p>因此阅读 UPS C 工程时，要把“收到命令”和“执行命令”分开看：命令解析只产生意图，安全门控决定这个意图是否允许落地。</p><h2 id="物理直觉" tabindex="-1">物理直觉 <a class="header-anchor" href="#物理直觉" aria-label="Permalink to &quot;物理直觉&quot;">​</a></h2><p>命令解析像门卫看懂访客想做什么；安全门控像值班工程师判断现在能不能放行。访客说“我要清故障”并不代表设备立刻清故障，必须满足市电、负载、输出、故障原因等安全条件。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>command = parse(raw_command)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if command.type == READ_STATUS:</span></span>
<span class="line"><span>    request_telemetry_reply = 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if command.type == CLEAR_FAULT_REQUEST:</span></span>
<span class="line"><span>    request_clear_fault = 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if request_clear_fault and not safe_to_clear_fault:</span></span>
<span class="line"><span>    request_clear_fault = 0</span></span></code></pre></div><p>本课只用一个布尔量 <code>safe_to_clear_fault</code> 表示安全条件，真实工程可能由模式、输出反馈、故障原因、保持时间和人工确认共同决定。</p><h2 id="仿真观察" tabindex="-1">仿真观察 <a class="header-anchor" href="#仿真观察" aria-label="Permalink to &quot;仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_command_parser.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>默认生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_command_parser.png</span></span></code></pre></div><p>图中包含命令类型、遥测回复请求、清故障请求和安全门控状态。图内参数框说明命令序列：20 ms 的不安全清故障被拒绝，60 ms 的安全清故障被接受。默认不加 <code>--no-open</code> 时脚本会尝试自动打开图片；打不开时会打印完整路径。</p><h2 id="固件落地" tabindex="-1">固件落地 <a class="header-anchor" href="#固件落地" aria-label="Permalink to &quot;固件落地&quot;">​</a></h2><ul><li><code>UpsCommandType</code>：教学命令类型。</li><li><code>UPS_COMMAND_READ_STATUS</code>：读取状态命令。</li><li><code>UPS_COMMAND_CLEAR_FAULT_REQUEST</code>：清故障请求命令。</li><li><code>UpsCommand</code>：解析后的内部命令意图。</li><li><code>request_telemetry_reply</code>：是否需要回复通信帧（communication frame）。</li><li><code>request_clear_fault</code>：是否请求清除故障锁存。</li><li><code>UpsCommand_Parse()</code>：把原始命令转换成内部意图。</li><li><code>UpsCommand_ApplySafetyGate()</code>：在安全条件不满足时拦截清故障请求。</li></ul><p>真实工程中还会有校验、超时、权限、主从地址、协议状态机和错误响应。本课不实现真实协议，只训练“解析”和“安全门控”的边界。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>错误理解：通信命令解析成功就应该立即执行。<br> 正确理解：解析成功只说明看懂了命令，不代表动作安全。</li><li>错误理解：清故障只是把标志清零。<br> 正确理解：清故障会影响系统重新启动和输出许可，必须经过安全条件检查。</li><li>错误理解：可以把导师给的真实命令字记到学习仓库。<br> 正确理解：不能记录公司内部通信命令，只能记录通用解析流程和安全边界。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能运行 <code>python simulations\\python\\ups_command_parser.py --no-open</code> 并打开 <code>simulations/results/ups_command_parser.png</code>。</li><li>能解释命令解析和安全门控的区别。</li><li>能解释为什么 <code>CLEAR_FAULT_REQUEST</code> 不能直接清除故障锁存。</li><li>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>command_parser</code> 输出。</li><li>能基于 <code>command_parser.c -&gt; UpsCommand_ApplySafetyGate()</code> 准备导师问题。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><ul><li>我用 <code>command_parser.c -&gt; UpsCommand_ApplySafetyGate()</code> 把清故障请求和安全条件分开。真实工程里清故障通常需要检查哪些通用条件？</li><li>我用 <code>simulations/results/ups_command_parser.png</code> 看到不安全清故障被拒绝。真实工程中拒绝命令时通常会回复错误码、保持沉默，还是上报当前状态？</li><li>我不会记录公司内部通信命令，只想确认阅读方式：看真实工程通信模块时，应先找命令解析表、安全门控入口，还是故障复位流程？</li></ul>`,29)])])}const u=e(l,[["render",i]]);export{h as __pageData,u as default};
